puedes crear el un dashboard con el siguiente codigo import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LineChart, Line, BarChart, Bar, ScatterChart, Scatter, XAxis, YAxis, 
  CartesianGrid, Tooltip, Legend, ResponsiveContainer, ComposedChart, Area 
} from 'recharts';
import { 
  Upload, X, TrendingUp, BarChart2, PieChart, Download, Loader, 
  ZoomIn, Menu, CheckCircle, Calendar, Filter, MessageSquare, Send, 
  Activity, ArrowUpRight, ArrowDownRight, FileText, Egg
} from 'lucide-react';

// --- Constantes para API ---
const MODEL_NAME = 'gemini-2.5-flash-preview-09-2025';
const API_URL = `https://generativelanguage.googleapis.com/v1beta/models/${MODEL_NAME}:generateContent`;
const API_KEY = ""; // La clave se proporcionará automáticamente en el entorno de Canvas

// --- Hooks Personalizados ---

// Hook para cargar librerías externas (PDF)
const useScript = (url) => {
    const [status, setStatus] = useState(url ? 'loading' : 'idle');
    useEffect(() => {
        if (!url) { setStatus('idle'); return; }
        let script = document.querySelector(`script[src="${url}"]`);
        if (!script) {
            script = document.createElement('script');
            script.src = url; script.async = true;
            const handleLoad = () => setStatus('ready');
            const handleError = () => setStatus('error');
            script.addEventListener('load', handleLoad);
            script.addEventListener('error', handleError);
            document.body.appendChild(script);
            return () => { script.removeEventListener('load', handleLoad, handleError); };
        } else {
            const libName = url.includes('jspdf') ? 'jspdf' : 'html2canvas';
            if (window[libName]) { setStatus('ready'); } else {
                const handleLoad = () => setStatus('ready');
                script.addEventListener('load', handleLoad);
                return () => script.removeEventListener('load', handleLoad);
            }
        }
    }, [url]);
    return status;
};

// --- Generación de Datos Mock ---
const generateMockData = () => {
    const farms = ['Granja Sol', 'Granja Luna', 'Granja Estrella'];
    const sheds = ['A1', 'A2', 'B1', 'B2'];
    const ages = ['30', '45', '60', '75'];
    const breeds = ['Hy-Line', 'Lohmann', 'Shaver']; // Nueva columna 'Estirpe'
    const data = [];
    const endDate = new Date();
    // Generar datos para varios meses (ej. 6 meses)
    for (let i = 180; i >= 0; i--) { 
        for (const farm of farms) {
            const date = new Date();
            date.setDate(endDate.getDate() - i);
            data.push({
                date: date.toISOString().split('T')[0],
                farm: farm, 
                shed: sheds[Math.floor(Math.random() * sheds.length)], 
                age: ages[Math.floor(Math.random() * ages.length)],
                breed: breeds[Math.floor(Math.random() * breeds.length)], // Datos de Estirpe
                weight: 58 + Math.random() * 10 - 5, 
                breakingStrength: 3.5 + Math.random() * 1.5 - 0.75,
                shellThickness: 0.35 + Math.random() * 0.1 - 0.05, 
                yolkColor: 9 + Math.random() * 4 - 2,
                haughUnits: 75 + Math.random() * 20 - 10,
            });
        }
    }
    return data.sort((a, b) => new Date(a.date) - new Date(b.date));
};

const INITIAL_DATA = generateMockData();

// --- Funciones Auxiliares ---
const calculateAllStats = (data, key) => {
    const values = data.map(d => d[key]).filter(v => typeof v === 'number' && !isNaN(v));
    if (values.length === 0) return { mean: 0, std: 0, min: 0, max: 0 };
    const sum = values.reduce((acc, val) => acc + val, 0);
    const mean = sum / values.length;
    const sqDiffs = values.map(val => Math.pow(val - mean, 2));
    const avgSqDiff = sqDiffs.reduce((acc, val) => acc + val, 0) / values.length;
    const std = Math.sqrt(avgSqDiff);
    return { mean, std, min: Math.min(...values), max: Math.max(...values) };
};

const getHistogramData = (data, key, bins = 12) => {
    const values = data.map(d => d[key]).filter(v => typeof v === 'number' && !isNaN(v));
    if (values.length === 0) return [];
    const min = Math.min(...values); 
    const max = Math.max(...values);
    if (min === max) return [{ range: `${min.toFixed(2)}`, rangeLabel: `${min.toFixed(2)}`, count: values.length }];
    const binWidth = (max - min) / bins;
    const histogram = Array.from({ length: bins }, (_, i) => ({ 
        range: `${(min + i * binWidth).toFixed(1)}`,
        rangeLabel: `${(min + i * binWidth).toFixed(2)} - ${(min + (i + 1) * binWidth).toFixed(2)}`,
        count: 0 
    }));
    values.forEach(value => {
        let binIndex = Math.floor((value - min) / binWidth);
        if (binIndex === bins) binIndex--;
        if (histogram[binIndex]) histogram[binIndex].count++;
    });
    return histogram;
};

const METRIC_CONFIG = {
    weight: { name: 'Peso Huevo', color: '#3b82f6', unit: 'g', icon: Egg },
    breakingStrength: { name: 'Resistencia', color: '#ef4444', unit: 'kgf', icon: Activity },
    shellThickness: { name: 'Espesor', color: '#10b981', unit: 'mm', icon:  TrendingUp},
    yolkColor: { name: 'Color Yema', color: '#f59e0b', unit: 'Escala', icon: PieChart },
    haughUnits: { name: 'Unid. Haugh', color: '#6366f1', unit: 'HU', icon: BarChart2 },
};

// --- Componentes de Chat ---

// Componente para manejar el texto de respuesta y las citas.
const ChatMessage = ({ role, text, sources = [] }) => {
    const isModel = role === 'model';
    return (
        <div className={`flex mb-4 ${isModel ? 'justify-start' : 'justify-end'}`}>
            <div className={`max-w-3xl px-4 py-3 rounded-xl shadow-md ${
                isModel ? 'bg-slate-100 text-slate-800 rounded-tl-none' : 'bg-blue-600 text-white rounded-tr-none'
            }`}>
                <p className="whitespace-pre-wrap">{text}</p>
                {isModel && sources.length > 0 && (
                    <div className="mt-2 pt-2 border-t border-slate-300 text-xs text-slate-500">
                        <p className="font-semibold mb-1">Fuentes (Grounding):</p>
                        <ul className="list-disc pl-4 space-y-0.5">
                            {sources.map((s, index) => (
                                <li key={index}><a href={s.uri} target="_blank" rel="noopener noreferrer" className="hover:text-blue-600 underline truncate block">{s.title}</a></li>
                            ))}
                        </ul>
                    </div>
                )}
            </div>
        </div>
    );
};

// Componente de la caja de chat principal
const ChatBox = ({ chatHistory, onSubmit, isThinking, filters, averages }) => {
    const [input, setInput] = useState('');
    const endOfMessagesRef = useRef(null);
    const contextRef = useRef(null);

    // Scroll al final al recibir nuevo mensaje
    useEffect(() => {
        endOfMessagesRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [chatHistory]);

    // Crear el contexto de datos que se envía al modelo
    const dataContext = useMemo(() => {
        const avg = Object.keys(averages).map(key => 
            `${METRIC_CONFIG[key].name}: ${averages[key]} ${METRIC_CONFIG[key].unit}`
        ).join(', ');

        const filterContext = `Filtros Aplicados: Granja: ${filters.selectedFarm}, Caseta: ${filters.selectedShed}, Edad: ${filters.selectedAge}, Estirpe: ${filters.selectedBreed}. Rango de Fechas: ${new Date(filters.startDate).toLocaleDateString()} a ${new Date(filters.endDate).toLocaleDateString()}.`;
        const totalRecords = `Total de Piezas (Registros) en el contexto actual: ${filters.recordCount}.`;

        return `Contexto de Datos Actual:\n${filterContext}\n${totalRecords}\nPromedios Clave: ${avg}.`;
    }, [filters, averages]);

    // Función de envío
    const handleSubmit = (e) => {
        e.preventDefault();
        if (input.trim() === '' || isThinking) return;
        onSubmit(input, dataContext);
        setInput('');
    };

    return (
        // Altura ajustada para ocupar mejor el espacio en su propia vista
        <div className="bg-white rounded-xl shadow-lg border border-slate-100 flex flex-col h-[calc(100vh-200px)] min-h-[500px]">
            <div className="p-4 border-b border-slate-200 flex justify-between items-center">
                <h3 className="font-bold text-lg text-slate-800 flex items-center gap-2">
                    <MessageSquare size={20} className="text-blue-600"/> 
                    Asistente Avícola (Gemini)
                </h3>
            </div>

            {/* Contexto (Colapsable para no saturar la UI) */}
            <div className="text-xs p-3 bg-slate-50 border-b border-slate-200">
                <details ref={contextRef}>
                    <summary className="cursor-pointer font-medium text-slate-500 hover:text-slate-800 transition-colors">
                        Ver Contexto de Datos (Enviado al Experto)
                    </summary>
                    <pre className="mt-2 p-2 bg-white rounded-lg overflow-auto text-[10px] text-slate-600 border border-slate-300">
                        {dataContext}
                    </pre>
                </details>
            </div>


            {/* Historial de Chat */}
            <div className="flex-grow p-4 overflow-y-auto space-y-4">
                {chatHistory.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-slate-400 text-center">
                        <Egg size={40} className="mb-2"/>
                        <p className="text-sm">Pregúntale al experto sobre los promedios y tendencias.</p>
                        <p className="text-xs">(Ej: "¿Qué significa una Resistencia baja para esta estirpe?")</p>
                    </div>
                ) : (
                    chatHistory.map((msg, index) => (
                        <ChatMessage key={index} role={msg.role} text={msg.text} sources={msg.sources} />
                    ))
                )}
                {isThinking && (
                    <div className="flex justify-start mb-4">
                        <div className="bg-slate-100 px-4 py-3 rounded-xl rounded-tl-none shadow-md text-slate-500 flex items-center text-sm">
                            <Loader size={16} className="animate-spin mr-2"/>
                            Pensando...
                        </div>
                    </div>
                )}
                <div ref={endOfMessagesRef} />
            </div>

            {/* Input de Chat */}
            <form onSubmit={handleSubmit} className="p-4 border-t border-slate-200">
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        placeholder={isThinking ? "Esperando respuesta..." : "Escribe tu pregunta al experto..."}
                        className="flex-1 p-3 border border-slate-300 rounded-xl focus:ring-blue-500 focus:border-blue-500 disabled:bg-slate-50"
                        disabled={isThinking}
                    />
                    <button
                        type="submit"
                        disabled={isThinking || input.trim() === ''}
                        className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition-colors disabled:bg-blue-300"
                    >
                        <Send size={20} />
                    </button>
                </div>
            </form>
        </div>
    );
};

// --- Componentes de UI ---

const Modal = ({ message, onClose, type = 'info' }) => { 
    if (!message) return null; 
    const Icon = type === 'error' ? X : CheckCircle;
    const colorClass = type === 'error' ? 'text-red-600' : 'text-green-600';

    return (
        <div className="fixed inset-0 bg-black bg-opacity-60 backdrop-blur-sm flex items-center justify-center z-[60]">
            <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-md mx-4 transform transition-all scale-100">
                <div className="flex justify-between items-center mb-4">
                    <h3 className={`text-lg font-bold flex items-center gap-2 ${colorClass}`}>
                        <Icon size={20}/>
                        {type === 'error' ? 'Error de Carga' : 'Notificación'}
                    </h3>
                    <button onClick={onClose} className="text-gray-400 hover:text-gray-800 transition-colors"><X size={20} /></button>
                </div>
                <p className="text-gray-600 mb-6">{message}</p>
                <div className="text-right">
                    <button onClick={onClose} className="bg-slate-900 text-white rounded-lg py-2 px-6 hover:bg-slate-800 transition-colors font-medium text-sm">
                        Aceptar
                    </button>
                </div>
            </div>
        </div>
    ); 
};

const ChartModal = ({ chartConfig, onClose }) => {
    useEffect(() => {
        const handleKeyDown = (event) => { if (event.key === 'Escape') onClose(); };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [onClose]);

    if (!chartConfig) return null;
    // La data ya debe venir pre-procesada si es un histograma o promedios mensuales
    const { type, title, data, dataKey, color, xAxisKey } = chartConfig; 

    const renderChart = () => {
        // La clave del Eje X se pasa explícitamente, o usa 'date' por defecto
        const currentXAxisKey = xAxisKey || 'date'; 

        const commonProps = { data, margin: { top: 20, right: 30, left: 20, bottom: 20 } };

        // Componente de Gráfico: BarChart para histograma/barras, LineChart para series de tiempo
        const ChartComponent = type === 'histogram' || type === 'bar' ? BarChart : LineChart;
        const DataComponent = type === 'histogram' || type === 'bar' ? Bar : Line;

        // Determinar la clave de la métrica (si es histograma, la dataKey es 'count')
        const chartDataKey = type === 'histogram' ? 'count' : dataKey;

        // Determinar el título para el tooltip/leyenda
        const chartDataName = type === 'histogram' ? 'Conteo de Frecuencia' : (METRIC_CONFIG[dataKey]?.name || title);
        const chartDataUnit = type === 'histogram' ? 'piezas' : (METRIC_CONFIG[dataKey]?.unit || '');

        return (
            <ChartComponent {...commonProps}>
                <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
                <XAxis 
                    dataKey={currentXAxisKey} // Usa la clave de Eje X correcta
                    stroke="#64748b" 
                    tick={{fontSize: 12}} 
                    // Formato para fechas (si es serie de tiempo) o etiquetas de rango/mes
                    tickFormatter={currentXAxisKey === 'date' ? (val) => val.split('-').slice(1).join('/') : undefined}
                    angle={currentXAxisKey !== 'date' ? -45 : 0} // Rotar ticks para histograma/meses
                    textAnchor={currentXAxisKey !== 'date' ? 'end' : 'middle'}
                    height={currentXAxisKey !== 'date' ? 60 : 30}
                />
                <YAxis 
                    stroke="#64748b" 
                    domain={['auto', 'auto']} 
                    tickFormatter={(t) => t.toFixed(type === 'line' ? 1 : 0)} 
                />
                <Tooltip 
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} 
                    // Formateador para mostrar el valor con la unidad
                    formatter={(value) => [`${value.toFixed(type === 'line' ? 2 : 0)} ${chartDataUnit}`, chartDataName]}
                    labelFormatter={(label) => currentXAxisKey === 'rangeLabel' ? `Rango: ${label}` : label} // Etiqueta específica para Histograma
                />
                <Legend />
                <DataComponent 
                    type={type === 'line' ? 'monotone' : undefined} 
                    dataKey={chartDataKey} // Usa 'count' o la dataKey
                    stroke={type === 'line' ? color : undefined} 
                    fill={type !== 'line' ? color : undefined}
                    strokeWidth={type === 'line' ? 3 : 0} 
                    dot={type === 'line' ? false : undefined} 
                    activeDot={type === 'line' ? { r: 8 } : undefined} 
                    name={chartDataName}
                    radius={type !== 'line' ? [4, 4, 0, 0] : undefined}
                />
            </ChartComponent>
        );
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-75 backdrop-blur-sm flex items-center justify-center z-50 p-4" onClick={onClose}>
            <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-5xl h-[80vh] flex flex-col" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-6 border-b pb-4">
                    <div>
                        <h3 className="text-2xl font-bold text-gray-800">{title}</h3>
                        <p className="text-sm text-gray-500">Vista detallada y ampliada</p>
                    </div>
                    <button onClick={onClose} className="bg-gray-100 p-2 rounded-full hover:bg-gray-200 transition-colors"><X size={24} /></button>
                </div>
                <div className="flex-grow w-full h-full">
                     <ResponsiveContainer width="100%" height="100%">
                        {renderChart()}
                     </ResponsiveContainer>
                </div>
            </div>
        </div>
    );
};

/**
 * Componente para mostrar el conteo total de registros.
 * NO muestra mini-gráfica ni tendencia.
 */
const CountCard = ({ title, value, icon: Icon, color }) => (
    <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-center relative overflow-hidden group">
        <div className="flex justify-between items-center mb-4">
            <div className={`p-3 rounded-lg bg-opacity-10`} style={{ backgroundColor: `${color}20` }}>
                <Icon size={24} style={{ color: color }} />
            </div>
        </div>
        <div>
            <h3 className="text-sm font-medium text-slate-500">{title}</h3>
            <p className="text-3xl font-bold text-slate-800 mt-1">
                {value.toLocaleString()} 
            </p>
            <p className="text-xs text-slate-400 mt-1">Total de registros filtrados</p>
        </div>
    </div>
);


const MetricCard = ({ title, value, data, dataKey, color, unit, icon: Icon, onZoom }) => {
    // Calculamos la tendencia basándonos en los últimos 2 puntos
    // NOTA: Esta tendencia es solo un indicador visual y simplificado para el dashboard.
    const trend = data.length >= 2 ? data[data.length - 1][dataKey] - data[data.length - 2][dataKey] : 0;
    const isPositive = trend >= 0;

    return (
        <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-shadow relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-2 opacity-0 group-hover:opacity-100 transition-opacity">
                 <button onClick={onZoom} className="p-1.5 bg-gray-50 text-gray-500 rounded-md hover:text-blue-600 hover:bg-blue-50">
                    <ZoomIn size={16} />
                </button>
            </div>

            <div className="flex justify-between items-start mb-4">
                <div className={`p-3 rounded-lg bg-opacity-10`} style={{ backgroundColor: `${color}20` }}>
                    <Icon size={24} style={{ color: color }} />
                </div>
                {/* Indicador de Tendencia */}
                <div className={`flex items-center text-xs font-semibold px-2 py-1 rounded-full ${isPositive ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                    {isPositive ? <ArrowUpRight size={14} className="mr-1"/> : <ArrowDownRight size={14} className="mr-1"/>}
                    {Math.abs(trend).toFixed(2)}%
                </div>
            </div>

            <div>
                <h3 className="text-sm font-medium text-slate-500">{title}</h3>
                <p className="text-3xl font-bold text-slate-800 mt-1">
                    {value} <span className="text-sm font-normal text-slate-400">{unit}</span>
                </p>
            </div>

            {/* Mini Gráfica */}
            <div className="h-16 mt-4 -mx-2">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={data}>
                        <Line type="monotone" dataKey={dataKey} stroke={color} strokeWidth={2} dot={false} />
                    </LineChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
};

const DashboardChart = ({ title, data, dataKey, color, chartId, onDownload, scriptsReady, onZoom, type = 'line' }) => (
    <div id={chartId} className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col">
        <div className="flex justify-between items-center mb-6">
            <div>
                <h3 className="text-lg font-bold text-slate-800">{title}</h3>
                <p className="text-xs text-slate-400">Últimos datos registrados</p>
            </div>
            <div className="flex gap-2">
                <button onClick={onZoom} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors">
                    <ZoomIn size={18} />
                </button>
                <button 
                    onClick={() => onDownload(chartId, `${title.replace(/\s+/g, '-')}.pdf`)} 
                    disabled={!scriptsReady}
                    className="p-2 text-slate-400 hover:text-green-600 hover:bg-green-50 rounded-lg transition-colors disabled:opacity-30"
                >
                    <Download size={18} />
                </button>
            </div>
        </div>
        <div className="flex-grow min-h-[250px]">
            <ResponsiveContainer width="100%" height="100%">
                {type === 'line' ? (
                     <AreaChartWithGradient data={data} dataKey={dataKey} color={color} unit={METRIC_CONFIG[dataKey]?.unit} />
                ) : (
                    <BarChart data={getHistogramData(data, dataKey)} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        {/* El histograma usa 'rangeLabel' para el tooltip, pero 'range' para el eje X por defecto en esta vista */}
                        <XAxis dataKey="range" stroke="#94a3b8" tick={{fontSize: 10}} tickLine={false} axisLine={false} dy={10} />
                        <YAxis stroke="#94a3b8" tick={{fontSize: 10}} tickLine={false} axisLine={false} />
                        <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} />
                        <Bar dataKey="count" fill={color} radius={[4, 4, 0, 0]} />
                    </BarChart>
                )}
            </ResponsiveContainer>
        </div>
    </div>
);

const AreaChartWithGradient = ({ data, dataKey, color, unit }) => (
    <AreaChartWrapper data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
        <defs>
            <linearGradient id={`color${dataKey}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={color} stopOpacity={0.2}/>
                <stop offset="95%" stopColor={color} stopOpacity={0}/>
            </linearGradient>
        </defs>
        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
        <XAxis dataKey="date" stroke="#94a3b8" tick={{fontSize: 10}} tickFormatter={(val) => val.split('-').slice(1).join('/')} tickLine={false} axisLine={false} dy={10} />
        <YAxis stroke="#94a3b8" tick={{fontSize: 10}} domain={['auto', 'auto']} tickLine={false} axisLine={false} />
        <Tooltip contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} itemStyle={{ color: color }} />
        <Area type="monotone" dataKey={dataKey} stroke={color} fillOpacity={1} fill={`url(#color${dataKey})`} strokeWidth={2} name={METRIC_CONFIG[dataKey]?.name} unit={unit} />
    </AreaChartWrapper>
);

const AreaChartWrapper = ComposedChart;

const SidebarItem = ({ icon: Icon, label, active, onClick }) => (
    <button 
        onClick={onClick}
        className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all duration-200 mb-1 ${
            active 
            ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
            : 'text-slate-600 hover:bg-slate-100 hover:text-slate-800' // Ajustado para fondo blanco
        }`}
    >
        <Icon size={20} />
        <span>{label}</span>
    </button>
);

const StatRow = ({ label, value }) => (
    <div className="flex justify-between py-2 border-b border-gray-50 last:border-0">
        <span className="text-gray-500">{label}</span>
        <span className="font-semibold text-gray-900">{value}</span>
    </div>
);

// --- Componente de Gráfico de Promedios Mensuales (ACTUALIZADO con Zoom) ---
const MonthlyAverageChart = ({ monthlyAverageData, scriptsReady, onDownload, onZoom }) => {

    // Lista de claves de métricas a graficar (los 5 solicitados)
    const metricKeys = Object.keys(METRIC_CONFIG);

    if (monthlyAverageData.length === 0) {
        return (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 h-96 flex items-center justify-center">
                <p className="text-slate-500">No hay datos suficientes para calcular los promedios mensuales en el rango seleccionado.</p>
            </div>
        );
    }

    // Renderiza una cuadrícula con un gráfico de barras por cada métrica
    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {metricKeys.map((key) => {
