                                        tickLine={false} 
                                        axisLine={false} 
                                        tickFormatter={(t) => t.toFixed(1)} 
                                        // Asegura que el eje Y se ajuste dinámicamente
                                        domain={['auto', 'auto']} 
                                    />
                                    <Tooltip 
                                        cursor={{fill: '#f8fafc'}} 
                                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                        // Formateador para mostrar el valor con la unidad
                                        formatter={(value) => [`${value.toFixed(2)} ${config.unit}`, config.name]}
                                    />
                                    {/* La barra usa la clave de la métrica y su color */}
                                    <Bar dataKey={key} fill={config.color} radius={[4, 4, 0, 0]} name={config.name} />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                );
            })}
        </div>
    );
};
// --- FIN Componente de Gráfico de Promedios Mensuales (ACTUALIZADO con Zoom) ---


// --- Componente Principal ---

export default function App() {
    const jspdfStatus = useScript('https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js');
    const html2canvasStatus = useScript('https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js');
    const scriptsReady = jspdfStatus === 'ready' && html2canvasStatus === 'ready';

    const [dashboardData, setDashboardData] = useState(INITIAL_DATA);

    // Estados de Filtro Agregados/Actualizados
    const [selectedFarm, setSelectedFarm] = useState('Todos');
    const [selectedShed, setSelectedShed] = useState('Todos');
    const [selectedAge, setSelectedAge] = useState('Todos'); // Filtro de Edad
    const [selectedBreed, setSelectedBreed] = useState('Todos'); // Filtro de Estirpe

    // Fechas (Defaults: Últimos 30 días)
    const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]);
    const [startDate, setStartDate] = useState(() => { const d = new Date(); d.setDate(d.getDate() - 29); return d.toISOString().split('T')[0]; });

    // UI State
    const [fileName, setFileName] = useState('');
    const [modal, setModal] = useState({ show: false, message: '', type: 'info' });
    // Estado inicial en 'dashboard'
    const [activeTab, setActiveTab] = useState('dashboard'); 
    const [isDownloading, setIsDownloading] = useState(false);
    const [zoomedChart, setZoomedChart] = useState(null);
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

    // CHAT State
    const [chatHistory, setChatHistory] = useState([]);
    const [isThinking, setIsThinking] = useState(false);

    // Listas Derivadas para Filtros (Actualizadas)
    const FARMS = useMemo(() => ['Todos', ...Array.from(new Set(dashboardData.map(d => d.farm).filter(Boolean)))], [dashboardData]);
    const SHEDS = useMemo(() => ['Todos', ...Array.from(new Set(dashboardData.map(d => d.shed).filter(Boolean)))], [dashboardData]);
    const AGES = useMemo(() => ['Todos', ...Array.from(new Set(dashboardData.map(d => d.age).filter(Boolean)))].sort((a, b) => { 
        if (a === 'Todos') return -1; if (b === 'Todos') return 1; return parseInt(a) - parseInt(b);
    }), [dashboardData]);
    const BREEDS = useMemo(() => ['Todos', ...Array.from(new Set(dashboardData.map(d => d.breed).filter(Boolean))).sort()], [dashboardData]);

    // Filtrado de Datos Principal (Actualizado para Edad y Estirpe)
    const filteredData = useMemo(() => {
        const start = new Date(startDate);
        const end = new Date(endDate);
        // Ajustamos la fecha de fin al final del día para incluir el último registro
        end.setHours(23, 59, 59, 999); 

        return dashboardData.filter(d => {
            const dDate = new Date(d.date);
            const dateMatch = dDate >= start && dDate <= end;
            const farmMatch = selectedFarm === 'Todos' || d.farm === selectedFarm;
            const shedMatch = selectedShed === 'Todos' || d.shed === selectedShed;
            const ageMatch = selectedAge === 'Todos' || d.age === selectedAge;
            const breedMatch = selectedBreed === 'Todos' || d.breed === selectedBreed;

            return dateMatch && farmMatch && shedMatch && ageMatch && breedMatch;
        });
    }, [dashboardData, selectedFarm, selectedShed, selectedAge, selectedBreed, startDate, endDate]);


    // --- CÁLCULO DE PROMEDIOS MENSUALES (Lógica para las 5 métricas) ---
    const getMonthKey = (dateString) => dateString.substring(0, 7); // YYYY-MM

    const monthlyAverageData = useMemo(() => {
        const grouped = {};

        filteredData.forEach(d => {
            const monthKey = getMonthKey(d.date);
            if (!grouped[monthKey]) {
                grouped[monthKey] = { count: 0, dateLabel: monthKey.replace('-', '/') };
                Object.keys(METRIC_CONFIG).forEach(key => grouped[monthKey][key] = 0);
            }

            grouped[monthKey].count++;
            Object.keys(METRIC_CONFIG).forEach(key => {
                // Solo suma si es un número válido
                if (typeof d[key] === 'number' && d[key] !== null) {
                    grouped[monthKey][key] += d[key];
                }
            });
        });

        const averages = Object.keys(grouped).map(monthKey => {
            const totalCount = grouped[monthKey].count;
            const avg = { month: monthKey, dateLabel: grouped[monthKey].dateLabel };
            Object.keys(METRIC_CONFIG).forEach(key => {
                // Calcula el promedio y lo redondea a 2 decimales
                avg[key] = totalCount > 0 ? parseFloat((grouped[monthKey][key] / totalCount).toFixed(2)) : 0;
            });
            return avg;
        });

        // Ordena por mes
        return averages.sort((a, b) => new Date(a.month) - new Date(b.month));
    }, [filteredData]);
    // --- FIN CÁLCULO DE PROMEDIOS MENSUALES ---


    // Cálculo de Promedios Globales para Cards
    const globalAverages = useMemo(() => {
        const avg = {};
        Object.keys(METRIC_CONFIG).forEach(key => {
            const result = calculateAllStats(filteredData, key);
            avg[key] = result.mean.toFixed(2);
        });
        return avg;
    }, [filteredData]);

    // Datos de Filtro para el Chat
    const filterContextData = useMemo(() => ({
        selectedFarm, selectedShed, selectedAge, selectedBreed, startDate, endDate, recordCount: filteredData.length
    }), [selectedFarm, selectedShed, selectedAge, selectedBreed, startDate, endDate, filteredData.length]);


    // --- FUNCIÓN DE CHAT CON API ---
    const handleChatSubmit = async (query, dataContext) => {
        setIsThinking(true);
        setChatHistory(prev => [...prev, { role: 'user', text: query, sources: [] }]);

        const systemPrompt = `Eres un experto en avicultura y análisis de calidad de huevo (Egg Quality Monitor). Tu tarea es interpretar los datos estadísticos proporcionados a continuación, responder la pregunta del usuario con claridad y utilizando un tono profesional y accesible (en español). Si es necesario, usa tus conocimientos de avicultura para contextualizar los resultados.

        Instrucciones:
        1. Responde a la pregunta del usuario.
        2. Analiza el 'Contexto de Datos Actual' que se te proporciona para basar tu respuesta en los filtros y promedios actuales.
        3. Siempre sé conciso y ve al punto.
        4. Usa formato Markdown solo para negritas y listas.`;

        const userQuery = `Basándote en el siguiente contexto de datos, responde mi pregunta.

        --- CONTEXTO DE DATOS ACTUAL ---
        ${dataContext}
        --- FIN CONTEXTO ---

        Mi pregunta es: ${query}`;

        const payload = {
            contents: [{ parts: [{ text: userQuery }] }],
            tools: [{ "google_search": {} }],
            systemInstruction: { parts: [{ text: systemPrompt }] },
        };

        let resultText = "Lo siento, hubo un error al obtener la respuesta del modelo.";
        let sources = [];
        let attempts = 0;
        const maxAttempts = 3;

        while (attempts < maxAttempts) {
            try {
                const response = await fetch(API_URL, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(payload)
                });

                if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

                const result = await response.json();
                const candidate = result.candidates?.[0];

                if (candidate && candidate.content?.parts?.[0]?.text) {
                    resultText = candidate.content.parts[0].text;
                    const groundingMetadata = candidate.groundingMetadata;
                    if (groundingMetadata && groundingMetadata.groundingAttributions) {
                        sources = groundingMetadata.groundingAttributions
                            .map(attribution => ({
                                uri: attribution.web?.uri,
                                title: attribution.web?.title,
                            }))
                            .filter(source => source.uri && source.title); 
                    }
                    break; // Salir del bucle si es exitoso
                }
            } catch (error) {
                console.error(`Attempt ${attempts + 1} failed:`, error);
                if (attempts < maxAttempts - 1) {
                    const delay = Math.pow(2, attempts) * 1000; // 1s, 2s, 4s
                    await new Promise(resolve => setTimeout(resolve, delay));
                }
            }
            attempts++;
        }

        setChatHistory(prev => [...prev, { role: 'model', text: resultText, sources: sources }]);
        setIsThinking(false);
    };
    // --- FIN FUNCIÓN DE CHAT CON API ---

    // CSV Parse Logic (Ajustada para robustez en parseo numérico)
    const handleFileChange = (event) => {
        const file = event.target.files[0];
        if (!file) return;
        setFileName(file.name);
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const content = e.target.result;
                const lines = content.split(/[\r\n]+/).filter(line => line.trim() !== '');
                if (lines.length < 2) throw new Error("Archivo vacío o sin datos.");

                const delimiter = lines[0].includes(';') ? ';' : lines[0].includes('\t') ? '\t' : ',';
                // Convertimos headers a minúsculas, removemos tildes y caracteres no esenciales para mejorar el matching
                const normalize = (str) => str.toLowerCase().replace(/[.\s]/g, '');
                const headers = lines[0].split(delimiter).map(h => normalize(h.trim()));

                // Mapeo ACTUALIZADO con las columnas que proporcionaste
                const map = { 
                    'fecha': 'date',
                    'granja': 'farm',
                    'caseta': 'shed',
                    'edad': 'age',
                    'peso': 'weight',
                    'resistencia': 'breakingStrength', // Resistencia mapeado
                    'altura': 'height',
                    'unidadeshaugh': 'haughUnits',
                    'coloryema': 'yolkColor',
                    'grosorcascaron': 'shellThickness',
                    'huevoconsangre': 'bloodSpot',
                    'metaqualix': 'metaqualixId',
                    'cliente': 'client',
                    'estirpe': 'breed', // Estirpe mapeado
                    'nde hvo': 'eggCount'
                };

                const dataIndex = {};
                headers.forEach((h, i) => {
                    Object.keys(map).forEach(key => { 
                        // Usamos includes para manejar variaciones como 'resistencia_media'
                        if(h.includes(key)) dataIndex[map[key]] = i; 
                    });
                });

                if (dataIndex.date === undefined) throw new Error("Columna 'Fecha' no encontrada. Asegúrate de que el archivo es CSV/TSV.");

                const newData = lines.slice(1).map(line => {
                    const cols = line.split(delimiter);
                    const row = {};
                    Object.keys(dataIndex).forEach(key => {
                        let val = cols[dataIndex[key]];
                        if(val) val = val.trim();

                        // Parseo numérico para métricas (incluyendo Resistencia)
                        if (['weight', 'breakingStrength', 'shellThickness', 'yolkColor', 'haughUnits', 'height', 'bloodSpot'].includes(key)) {
                            // Intentamos limpiar y convertir. Acepta ',' como decimal.
                            const numValue = parseFloat(val?.replace(',', '.') || 'NaN');
                            row[key] = isNaN(numValue) ? null : numValue;
                        } else if (key === 'date') {
                             // Asumimos que si viene como "date" puede ser ISO (yyyy-mm-dd) o dd/mm/yyyy
                            if (val && val.includes('/')) {
                                const parts = val.split('/');
                                // Convierte dd/mm/yyyy -> yyyy-mm-dd
                                row[key] = `${parts[2]}-${parts[1]}-${parts[0]}`; 
                            } else {
                                row[key] = val; 
                            }
                        } else {
                            row[key] = val;
                        }
                    });
                    return row;
                }).filter(r => r.date && r.farm && r.shed); // Validar filas mínimas

                if (newData.length === 0) throw new Error("No se pudo extraer data válida de las filas.");

                setDashboardData(newData.sort((a, b) => new Date(a.date) - new Date(b.date)));
                setModal({ show: true, message: `Datos cargados exitosamente. ${newData.length} registros procesados.`, type: 'info' });
            } catch (err) {
                setModal({ show: true, message: `Error al procesar el archivo: ${err.message}`, type: 'error' });
            }
        };
        reader.readAsText(file); 
    };

    // PDF Download Handler
    const handleDownload = async (elementId, filename) => {
        if (!scriptsReady) { setModal({ show: true, message: "Librerías cargando...", type: 'info' }); return; }
        const element = document.getElementById(elementId);
        if (!element) return;
        setIsDownloading(true);
        try {
            const canvas = await window.html2canvas(element, { backgroundColor: '#ffffff', scale: 2 });
            const imgData = canvas.toDataURL('image/png');
            const { jsPDF } = window.jspdf;

            // Determinar orientación basada en el tamaño del elemento, aunque se forzará paisaje
            const orientation = canvas.width > canvas.height ? 'landscape' : 'portrait';
            const pdf = new jsPDF(orientation, 'px', [canvas.width, canvas.height]);
            pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);
            pdf.save(filename);
        } catch (error) {
            console.error("Error al generar PDF:", error);
            setModal({ show: true, message: "Error al generar PDF", type: 'error' });
        } finally {
            setIsDownloading(false);
        }
    };

    // Función de Zoom para Histogramas y Gráficas de Línea
    const handleChartZoom = (type, key, title, data = filteredData) => {
        if (type === 'histogram') {
            // **CORRECCIÓN AQUÍ:** Pasar los datos ya procesados para el histograma
            setZoomedChart({ 
                type: 'histogram', 
                title: `Histograma ${title}`, 
                data: getHistogramData(data, key), 
                dataKey: key, 
                color: METRIC_CONFIG[key].color, 
                xAxisKey: 'rangeLabel' // Usar la etiqueta de rango completo en el eje X
            });
        } else {
            setZoomedChart({ 
                type: type, 
                title: title, 
                data: data, 
                dataKey: key, 
                color: METRIC_CONFIG[key].color,
                xAxisKey: 'date'
            });
        }
    };


    return (
        <div className="flex min-h-screen bg-slate-50 font-sans text-slate-800">
            {/* --- Sidebar --- */}
            <aside className={`fixed inset-y-0 left-0 z-40 w-64 bg-white text-slate-700 transform transition-transform duration-300 ease-in-out ${mobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 border-r border-slate-200`}>
                <div className="p-6 flex items-center gap-3 border-b border-slate-200">
                    <Egg className="text-cyan-600" size={32} />
                    <div>
                        <h1 className="text-xl font-bold leading-none">
                            <span className="text-cyan-600">Egg</span>
                            <span className="text-yellow-600">Monitor</span>
                        </h1>
                        <span className="text-xs text-slate-500">Quality Dashboard</span>
                    </div>
                </div>

                <nav className="p-4 space-y-2">
                    <p className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Vistas</p>
                    <SidebarItem icon={Activity} label="Dashboard" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
                    <SidebarItem icon={BarChart2} label="Histogramas" active={activeTab === 'histograms'} onClick={() => setActiveTab('histograms')} />
                    <SidebarItem icon={TrendingUp} label="Promedios Mensuales" active={activeTab === 'monthly-averages'} onClick={() => setActiveTab('monthly-averages')} /> 
                    <SidebarItem icon={FileText} label="Resumen Datos" active={activeTab === 'summary'} onClick={() => setActiveTab('summary')} />

                    {/* NUEVA VISTA CHAT */}
                    <SidebarItem icon={MessageSquare} label="Asistente Avícola" active={activeTab === 'chat'} onClick={() => setActiveTab('chat')} />

                </nav>

                {/* Filtros */}
                <div className="p-4 border-t border-slate-200">
                    <p className="px-4 text-xs font-semibold text-slate-700 uppercase tracking-wider mb-4">Filtros ({filteredData.length} registros)</p>

                    {/* Nota: Los filtros se mantienen en el sidebar para que apliquen a todas las vistas, incluyendo el chat. */}
                    <div className="space-y-4 px-2">

                        {/* Filtro de Fechas */}
                        <div>
                            <label className="block text-xs mb-1 text-slate-700 flex items-center gap-1"><Calendar size={12}/> Rango de Fechas</label>
                            <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full bg-slate-100 border border-slate-300 rounded text-xs text-slate-900 p-2 mb-2 focus:ring-blue-500 focus:border-blue-500" />
                            <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="w-full bg-slate-100 border border-slate-300 rounded text-xs text-slate-900 p-2 focus:ring-blue-500 focus:border-blue-500" />
                        </div>

                        {/* Filtro de Granja */}
                        <div>
                            <label className="block text-xs mb-1 text-slate-700">Granja</label>
                            <select value={selectedFarm} onChange={e => setSelectedFarm(e.target.value)} className="w-full bg-slate-100 border border-slate-300 rounded text-sm text-slate-900 p-2 focus:ring-blue-500 focus:border-blue-500">
                                {FARMS.map(f => <option key={f} value={f}>{f}</option>)}
                            </select>
                        </div>

                        {/* Filtro de Caseta */}
                        <div>
                            <label className="block text-xs mb-1 text-slate-700">Caseta</label>
                            <select value={selectedShed} onChange={e => setSelectedShed(e.target.value)} className="w-full bg-slate-100 border border-slate-300 rounded text-sm text-slate-900 p-2 focus:ring-blue-500 focus:border-blue-500">
                                {SHEDS.map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        </div>

                        {/* Filtro de Edad */}
                        <div>
                            <label className="block text-xs mb-1 text-slate-700">Edad</label>
                            <select value={selectedAge} onChange={e => setSelectedAge(e.target.value)} className="w-full bg-slate-100 border border-slate-300 rounded text-sm text-slate-900 p-2 focus:ring-blue-500 focus:border-blue-500">
                                {AGES.map(a => <option key={a} value={a}>{a}</option>)}
                            </select>
                        </div>

                        {/* Filtro de Estirpe */}
                        <div>
                            <label className="block text-xs mb-1 text-slate-700">Estirpe</label>
                            <select value={selectedBreed} onChange={e => setSelectedBreed(e.target.value)} className="w-full bg-slate-100 border border-slate-300 rounded text-sm text-slate-900 p-2 focus:ring-blue-500 focus:border-blue-500">
                                {BREEDS.map(b => <option key={b} value={b}>{b}</option>)}
                            </select>
                        </div>
                    </div>
                </div>

                 {/* Área de Subida */}
                 <div className="absolute bottom-0 w-full p-4 bg-white border-t border-slate-200">
                    <label className="flex items-center gap-2 cursor-pointer bg-blue-600 hover:bg-blue-700 text-white p-3 rounded-lg justify-center transition-colors">
                        <Upload size={18} />
                        <span className="text-sm font-medium">Subir CSV</span>
                        <input type="file" accept=".csv" onChange={handleFileChange} className="hidden" />
                    </label>
                    <p className="text-xs text-center mt-2 text-slate-500 truncate">{fileName}</p>
                </div>
            </aside>

            {/* --- Main Content --- */}
            <main className="flex-1 overflow-y-auto h-screen relative">
                {/* Header Mobile */}
                <div className="md:hidden bg-white p-4 shadow-sm flex justify-between items-center sticky top-0 z-30">
                    <div className="flex items-center gap-2">
                         <Egg className="text-cyan-600" size={24} />
                         <span className="font-bold">
                            <span className="text-cyan-600">Egg</span>
                            <span className="text-yellow-600">Monitor</span>
                         </span>
                    </div>
                    <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="text-slate-600">
                        <Menu size={24} />
                    </button>
                </div>

                <div className="p-4 md:p-8 max-w-7xl mx-auto pb-20">
                    <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
                        <div className="w-full">
                            {/* AJUSTE: Centrar y Agrandar el título en la vista 'dashboard' */}
                            <h2 className={`font-bold text-slate-800 mb-2 ${activeTab === 'dashboard' ? 'text-4xl text-center' : 'text-2xl'}`}>
                                {activeTab === 'dashboard' && (
                                    <>
                                        <span className="text-cyan-600">Egg</span>
                                        <span className="text-yellow-600">Monitor</span>
                                    </>
                                )}
                                {activeTab === 'histograms' && 'Distribución de Frecuencias'}
                                {activeTab === 'monthly-averages' && 'Análisis de Tendencia Mensual'}
                                {activeTab === 'summary' && 'Resumen Estadístico'}
                                {/* TÍTULO PARA LA VISTA CHAT */}
                                {activeTab === 'chat' && 'Asistente Avícola IA'}
                            </h2>
                            {/* AJUSTE: Centrar el subtítulo solo en el dashboard */}
