    const [input, setInput] = useState('');
    const endOfMessagesRef = useRef<HTMLDivElement>(null);
    const contextRef = useRef<HTMLDetailsElement>(null);

    useEffect(() => {
        endOfMessagesRef.current?.scrollIntoView({ behavior: "smooth" });
