                    )}

                    {/* VISTA RESUMEN (TABLA) */}
                    {activeTab === 'summary' && (
                        <div className="bg-white rounded-xl shadow-sm border border-slate-100 animate-in fade-in duration-500" id="summary-table">
                            <div className="p-6 border-b border-slate-100 flex justify-between">
