    };

    // --- Report Specific Data ---
    const [reportType, setReportType] = useState<'shed' | 'client'>('shed');
    const reportKey = reportType === 'shed' ? 'shed' : 'client';
    const reportLabel = reportType === 'shed' ? 'Caseta' : 'Cliente';

