                                        <div className="mt-4 text-xs text-slate-400">
                                            Filtros Aplicados: Granja ({selectedFarm}), Caseta ({selectedShed}), Edad ({selectedAge}), Estirpe ({selectedBreed}), Cliente ({selectedClient})
