                                    </div>
                                </div>


                                {uniqueReportEntities.length > 0 ? (
                                    <>
                                        {/* Section 1: Stats Table */}
                                        <div>
                                            <h2 className="text-2xl font-bold text-slate-700 mb-6">1. Tabla Comparativa de Estadísticas por {reportLabel}</h2>
