                                                                <td className={`px-4 py-3 font-bold text-slate-800 sticky left-0 z-10 ${
                                                                    highlightConfig.entity === row[reportKey] ? (highlightConfig.criteria === 'best' ? 'bg-green-50' : 'bg-red-50') : 'bg-white'
