                                                                {METRIC_KEYS.map(key => (
                                                                    <React.Fragment key={`${key}-${row[reportKey]}`}>
                                                                        <td className={`px-2 py-3 text-center text-slate-700 font-semibold border-l border-slate-200 transition-all ${
                                                                            highlightConfig.entity === row[reportKey] && highlightConfig.metricKey === key ? 'ring-2 ring-offset-0 ring-blue-500 rounded' : ''
                                                                        }`}>{row[`${key}_mean`]}</td>
                                                                        <td className="px-2 py-3 text-center text-slate-600">{row[`${key}_min`]}</td>
                                                                        <td className="px-2 py-3 text-center text-slate-600">{row[`${key}_max`]}</td>
                                                                        <td className="px-2 py-3 text-center text-slate-600">{row[`${key}_std`]}</td>
                                                                    </React.Fragment>
                                                                ))}
                                                            </tr>
                                                        ))}
                                                    </tbody>
                                                </table>
                                            </div>
                                        </div>

                                        {/* Section 2: Comparative Charts */}
                                        <div className="mt-12 pt-12 border-t-2 border-cyan-600">
                                            <h2 className="text-2xl font-bold text-slate-700 mb-8">2. Gráficos Comparativos de Promedios por {reportLabel}</h2>
                                            <div className="grid grid-cols-1 lg:grid-cols-2 gap-x-8 gap-y-12">
                                                {METRIC_KEYS.map(key => (
                                                    <div key={`compare-chart-${key}`} className="min-h-[300px]">
                                                        <h3 className="font-bold text-center text-slate-600 mb-4">{`Promedio de ${METRIC_CONFIG[key].name} por ${reportLabel}`}</h3>
                                                        <ResponsiveContainer width="100%" height={300}>
                                                            <BarChart data={comparativeChartData} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
                                                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                                                <XAxis dataKey={reportKey} stroke="#94a3b8" tick={{fontSize: 12}} />
                                                                <YAxis stroke="#94a3b8" tick={{fontSize: 10}} domain={['auto', 'auto']} tickFormatter={(t) => t.toFixed(1)} />
                                                                <Tooltip
                                                                    cursor={{fill: '#f8fafc'}}
                                                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                                                    formatter={(value: number) => [`${value.toFixed(2)} ${METRIC_CONFIG[key].unit}`, METRIC_CONFIG[key].name]}
                                                                />
                                                                <Bar dataKey={key} name={METRIC_CONFIG[key].name} radius={[4, 4, 0, 0]}>
                                                                    {comparativeChartData.map((entry, index) => (
                                                                        <Cell key={`cell-${index}`} fill={
                                                                            highlightConfig.entity === entry[reportKey] && highlightConfig.metricKey === key
                                                                            ? (highlightConfig.criteria === 'best' ? '#10b981' : '#ef4444')
                                                                            : METRIC_CONFIG[key].color
                                                                        } />
                                                                    ))}
                                                                </Bar>
                                                            </BarChart>
                                                        </ResponsiveContainer>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>

                                        {/* Section 3: Gauge Charts */}
                                        <div className="mt-12 pt-12 border-t-2 border-cyan-600">
                                            <h2 className="text-2xl font-bold text-slate-700 mb-8">3. Diagnóstico de Calidad por {reportLabel}</h2>
                                            <div className="space-y-12">
                                                {comparativeStatsData.map(entityData => (
                                                <div key={entityData[reportKey]}>
                                                    <h3 className="text-xl font-bold text-slate-800 mb-6 pb-2 border-b-2 border-slate-300">Diagnóstico para: <span className="text-blue-600">{entityData[reportKey]}</span></h3>
                                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
                                                    {METRIC_KEYS.map(key => (
                                                        <GaugeChart
                                                        key={`${entityData[reportKey]}-${key}`}
                                                        metricKey={key}
                                                        value={parseFloat(entityData[`${key}_mean`])}
                                                        standards={QUALITY_STANDARDS}
                                                        metricConfig={METRIC_CONFIG}
                                                        />
                                                    ))}
                                                    </div>
                                                </div>
                                                ))}
                                            </div>
                                        </div>
                                    </>
                                ) : (
                                    <div className="text-center py-20 text-slate-500">
                                        <ClipboardList size={40} className="mx-auto mb-4 text-slate-400"/>
                                        <h3 className="text-xl font-bold">No hay Datos para Reportar</h3>
                                        <p>Por favor, ajuste los filtros para incluir al menos un(a) {reportLabel.toLowerCase()} con registros.</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}
                </div>
            </main>

            {/* Modales */}
            {modal.show && <Modal message={modal.message} type={modal.type} onClose={() => setModal({ ...modal, show: false })} />}
            {zoomedChart && <ChartModal chartConfig={zoomedChart} onClose={() => setZoomedChart(null)} metricConfig={METRIC_CONFIG} />}
            {mobileMenuOpen && <div className="fixed inset-0 bg-black bg-opacity-50 z-30 md:hidden" onClick={() => setMobileMenuOpen(false)}></div>}
        </div>
    );
}

import { GoogleGenAI } from "@google/genai";
import { ChatSource } from "../types";

const SYSTEM_PROMPT = `Eres un experto en avicultura y análisis de calidad de huevo (Egg Quality Monitor). Tu tarea es interpretar los datos estadísticos proporcionados a continuación, responder la pregunta del usuario con claridad y utilizando un tono profesional y accesible (en español). Si es necesario, usa tus conocimientos de avicultura para contextualizar los resultados.

Instrucciones:
1. Responde a la pregunta del usuario.
2. Analiza el 'Contexto de Datos Actual' que se te proporciona para basar tu respuesta en los filtros y promedios actuales.
3. Siempre sé conciso y ve al punto.
4. Usa formato Markdown solo para negritas y listas.`;

export const sendMessageToGemini = async (
    userQuery: string, 
    dataContext: string
): Promise<{ text: string; sources: ChatSource[] }> => {
    // Inicializamos dentro de la función para asegurar que usamos la clave de API más reciente del entorno.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
        const fullPrompt = `Basándote en el siguiente contexto de datos, responde mi pregunta.

        --- CONTEXTO DE DATOS ACTUAL ---
        ${dataContext}
        --- FIN CONTEXTO ---

        Mi pregunta es: ${userQuery}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: fullPrompt,
            config: {
                systemInstruction: SYSTEM_PROMPT,
                tools: [{ googleSearch: {} }],
            }
        });

        const text = response.text || "No pude generar una respuesta.";

        // Extraer fragmentos de grounding (fuentes de búsqueda) si están disponibles
        let sources: ChatSource[] = [];
        const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

        if (groundingChunks) {
            sources = groundingChunks
                .filter(chunk => chunk.web?.uri && chunk.web?.title)
                .map(chunk => ({
                    uri: chunk.web?.uri,
                    title: chunk.web?.title
                }));
        }

        return { text, sources };

    } catch (error: any) {
        console.error("Gemini API Error Detallado:", error);

        // Manejo de errores comunes de configuración en despliegue
        if (error.message?.includes("API_KEY") || error.message?.includes("not found")) {
            throw new Error("Error de configuración: Asegúrate de que la clave de API (API_KEY) esté configurada correctamente en las variables de entorno de Vercel.");
        }

        throw error;
    }
};
